class Solution:
    def isValid(self, word: str) -> bool:
        # Condition 1: Minimum of 3 characters
        if len(word) < 3:
            return False

        vowels = set("aeiouAEIOU")
        has_vowel = False
        has_consonant = False

        for char in word:
            # Condition 2: Only digits (0-9) and English letters (uppercase and lowercase)
            # isalnum() checks if the character is alphanumeric (letter or digit)
            if not char.isalnum():
                return False

            # Check for vowels and consonants
            if char.isalpha():
                if char in vowels:
                    has_vowel = True
                else:
                    # A consonant is an English letter that is not a vowel
                    has_consonant = True

        # Condition 3 & 4: At least one vowel and at least one consonant
        return has_vowel and has_consonant

