from typing import List

class FenwickTree:
    """
    A Fenwick Tree (Binary Indexed Tree) to efficiently handle point updates
    and prefix sum queries.
    """
    def __init__(self, n: int):
        self.tree = [0] * (n + 1)

    def update(self, i: int, delta: int):
        """Adds delta to the element at index i (0-indexed)."""
        i += 1  # Convert to 1-indexed
        while i < len(self.tree):
            self.tree[i] += delta
            i += i & (-i)

    def query(self, i: int) -> int:
        """Returns the prefix sum from index 0 to i (0-indexed)."""
        i += 1  # Convert to 1-indexed
        s = 0
        while i > 0:
            s += self.tree[i]
            i -= i & (-i)
        return s

class Solution:
    def countOfPeaks(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        n = len(nums)
        bit = FenwickTree(n)

        def is_peak(i: int) -> bool:
            """
            Checks if the element at index i is a peak.
            A peak must be greater than its neighbors and cannot be the first or last element.
            """
            if 0 < i < n - 1:
                return nums[i-1] < nums[i] > nums[i+1]
            return False

        # Initialize the Fenwick tree with the initial peak statuses
        for i in range(1, n - 1):
            if is_peak(i):
                bit.update(i, 1)

        results = []
        for query in queries:
            if query[0] == 1:
                # Type 1 query: Count peaks in the subarray nums[l..r]
                l, r = query[1], query[2]
                # A peak in the subarray nums[l..r] must be at an index i such that l < i < r.
                # This is because the first and last elements of the subarray cannot be peaks.
                if r - l < 2:
                    results.append(0)
                else:
                    # The number of peaks in range [l+1, r-1] is bit.query(r-1) - bit.query(l)
                    results.append(bit.query(r - 1) - bit.query(l))
            else:
                # Type 2 query: Update nums[index] to val
                index, val = query[1], query[2]

                # Identify indices whose peak status might change due to the update at 'index'.
                # These are index-1, index, and index+1.
                affected = []
                for i in [index - 1, index, index + 1]:
                    if 0 < i < n - 1:
                        affected.append(i)

                # Remove the old peak status from the Fenwick tree for affected indices
                for i in affected:
                    if is_peak(i):
                        bit.update(i, -1)

                # Perform the update
                nums[index] = val

                # Add the new peak status to the Fenwick tree for affected indices
                for i in affected:
                    if is_peak(i):
                        bit.update(i, 1)

        return results

